// TestAttack_GoroutineLeakWithRapidCreateDestroy verifies no goroutine leaks with rapid create/close cycles
func TestAttack_GoroutineLeakWithRapidCreateDestroy(t *testing.T) {
	t.Parallel()

	before := runtime.NumGoroutine()

	// Create and destroy 100 CoalescingSets rapidly
	const iterations = 100
	for i := 0; i < iterations; i++ {
		ctx, cancel := context.WithCancel(context.Background())
		set := NewCoalescingSet(ctx, 10*time.Millisecond, func(keys []string) {})

		// Add some keys
		set.Add("entity-1")
		set.Add("entity-2")

		// Immediate close
		cancel()
		require.NoError(t, set.Close())
	}

	// Allow goroutines to terminate
	time.Sleep(200 * time.Millisecond)
	runtime.GC()
	time.Sleep(100 * time.Millisecond)

	after := runtime.NumGoroutine()

	// Allow for some variance, but should not grow significantly
	// Each iteration creates 1 goroutine, so 100 leaked = after == before + 100
	require.LessOrEqual(t, after, before+10,
		"goroutine leak detected: before=%d after=%d (delta=%d)",
		before, after, after-before)
}

// TestAttack_ConcurrentAddRemove verifies concurrent add/remove operations don't cause races
func TestAttack_ConcurrentAddRemove(t *testing.T) {
	t.Parallel()

	ctx := context.Background()
	var callbackCount atomic.Int32

	set := NewCoalescingSet(ctx, 100*time.Millisecond, func(keys []string) {
		callbackCount.Add(1)
	})
	defer set.Close()

	// Run concurrent add/remove operations
	const numGoroutines = 50
	const opsPerGoroutine = 100

	var wg sync.WaitGroup
	wg.Add(numGoroutines * 2)

	// Adders
	for i := 0; i < numGoroutines; i++ {
		go func(id int) {
			defer wg.Done()
			for j := 0; j < opsPerGoroutine; j++ {
				set.Add(generateEntityKey(id*opsPerGoroutine + j))
			}
		}(i)
	}

	// Removers (removing what adders add)
	for i := 0; i < numGoroutines; i++ {
		go func(id int) {
			defer wg.Done()
			for j := 0; j < opsPerGoroutine; j++ {
				set.Remove(generateEntityKey(id*opsPerGoroutine + j))
			}
		}(i)
	}

	wg.Wait()

	// System should not crash or deadlock
	// Allow callbacks to fire
	time.Sleep(300 * time.Millisecond)

	// Should have had at least one callback
	count := callbackCount.Load()
	assert.GreaterOrEqual(t, count, int32(1), "should have fired callbacks")
}

// TestAttack_CloseWhileCallbackRunning verifies Close() waits for callback to complete
func TestAttack_CloseWhileCallbackRunning(t *testing.T) {
	t.Parallel()

	ctx := context.Background()
	callbackRunning := make(chan struct{})
	callbackFinished := make(chan struct{})

	set := NewCoalescingSet(ctx, 50*time.Millisecond, func(keys []string) {
		close(callbackRunning)
		// Simulate long-running callback
		time.Sleep(150 * time.Millisecond)
		close(callbackFinished)
	})

	// Add entity to trigger callback
	set.Add("entity-1")

	// Wait for callback to start
	<-callbackRunning

	// Close while callback is running
	closeDone := make(chan struct{})
	go func() {
		require.NoError(t, set.Close())
		close(closeDone)
	}()

	// Close should wait for callback to finish
	select {
	case <-closeDone:
		// Verify callback actually finished
		select {
		case <-callbackFinished:
			// Good - callback completed before Close returned
		default:
			t.Fatal("Close() returned before callback finished")
		}
	case <-time.After(1 * time.Second):
		t.Fatal("Close() hung waiting for callback")
	}
}

// TestAttack_ZeroWindowRaceCondition verifies zero window doesn't cause TOCTOU with callback firing twice
// This was the original bug in Debouncer that CoalescingSet should NOT have.
func TestAttack_ZeroWindowRaceCondition(t *testing.T) {
	t.Parallel()

	ctx := context.Background()
	var callbackCount atomic.Int32
	var receivedBatches [][]string
	var mu sync.Mutex

	set := NewCoalescingSet(ctx, 0, func(keys []string) {
		callbackCount.Add(1)
		mu.Lock()
		receivedBatches = append(receivedBatches, keys)
		mu.Unlock()
	})
	defer set.Close()

	// Add same entity multiple times rapidly with zero window
	const iterations = 100
	for i := 0; i < iterations; i++ {
		set.Add("entity-1")
	}

	// Allow callbacks to fire
	time.Sleep(200 * time.Millisecond)

	// Verify entity-1 appears in at most ONE batch per window
	mu.Lock()
	defer mu.Unlock()

	entity1Count := 0
	for _, batch := range receivedBatches {
		for _, key := range batch {
			if key == "entity-1" {
				entity1Count++
			}
		}
	}

	// Despite 100 additions, entity-1 should appear limited number of times
	// (once per tick, not 100 times). Use generous threshold for slow CI.
	assert.LessOrEqual(t, entity1Count, 50,
		"entity should not appear 100 times (deduplication failed)")
}

// TestAttack_ConcurrentClose verifies multiple goroutines calling Close() simultaneously
func TestAttack_ConcurrentClose(t *testing.T) {
	t.Parallel()

	ctx := context.Background()
	set := NewCoalescingSet(ctx, 50*time.Millisecond, func(keys []string) {})

	// Add some keys
	set.Add("entity-1")

	// Multiple goroutines call Close() simultaneously
	const numClosers = 20
	var wg sync.WaitGroup
	wg.Add(numClosers)

	errors := make(chan error, numClosers)

	for i := 0; i < numClosers; i++ {
		go func() {
			defer wg.Done()
			err := set.Close()
			errors <- err
		}()
	}

	wg.Wait()
	close(errors)

	// All Close() calls should succeed (idempotent)
	for err := range errors {
		require.NoError(t, err, "Close() should be idempotent")
	}
}

